# DK FRT.  Fredericia gamle - Taulov
#
let ft = path("d3.dk.frt");

with detail = 3,
     railway = :first :double :removed
{
    with link = "point.dk.Fredericia-gamle", railway = :station, layer = -2 {
        track(ft[:fre - 0.5sw, :fre.ya + 1seg]);
        track(path("d3.dk.fps")[:fre.ya, :fre.ya + 1seg]);
        marker(:left :de.bf :removed, ft[:fre] << 0.5md);
    }

    with link = "line.dk.frt", layer = -2 {
        track(ft[:fre.ya + 0.99seg, :fre.zk]);
    }
}

